120	export default function ListerCampaigns() {
121	  const { user } = useAuth();
122	  const userId = user?.id ?? null;
123	  const handle = user?.username ?? '';
124	
125	  const [segment, setSegment] = useState<Segment>('active');
126	  const [rows, setRows] = useState<CampaignRow[]>([]);
127	  const [loading, setLoading] = useState(true);
128	  const [refreshing, setRefreshing] = useState(false);
129	  const [error, setError] = useState<string | null>(null);
130	
131	  const load = useCallback(async () => {
132	    if (!userId) return;
133	    setError(null);
134	    const { data, error: rpcError } = await supabase.rpc('list_my_campaigns');
135	    if (rpcError) {
136	      setError("Couldn't load campaigns.");
137	      setRows([]);
138	    } else {
139	      setRows(data ?? []);
140	    }
141	  }, [userId]);
142	
143	  useEffect(() => {
144	    setLoading(true);
145	    void load().finally(() => setLoading(false));
146	  }, [load]);
147	
148	  const onRefresh = useCallback(async () => {
149	    setRefreshing(true);
150	    await load();
151	    setRefreshing(false);
152	  }, [load]);
153	
154	  const onCreate = useCallback(() => {
155	    router.push('/(lister)/campaigns/new/step-1');
156	  }, []);
157	
158	  const byBucket = useMemo(() => {
159	    const map: Record<Segment, CampaignRow[]> = { active: [], inactive: [] };
160	    for (const r of rows) {
161	      map[SEGMENT_OF[r.status]].push(r);
162	    }
163	    return map;
164	  }, [rows]);
165	
166	  const counts = useMemo<Record<Segment, number>>(
167	    () => ({ active: byBucket.active.length, inactive: byBucket.inactive.length }),
168	    [byBucket],
169	  );
170	
171	  const visible = byBucket[segment];
172	
173	  return (
174	    <SafeAreaView style={styles.root}>
175	      <ScrollView
176	        contentContainerStyle={styles.scroll}
177	        refreshControl={
178	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
179	        }
180	      >
181	        <Text style={[textStyles.display, styles.header]}>Campaigns</Text>
182	        <SegmentControl active={segment} counts={counts} onChange={setSegment} />
183	
184	        {loading ? (
185	          <View style={styles.list} testID="campaigns-loading">
186	            <SkeletonCard />
187	            <SkeletonCard />
188	          </View>
189	        ) : error ? (
190	          <View style={styles.emptyBox}>
191	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
192	          </View>
193	        ) : visible.length === 0 ? (
194	          <View style={styles.emptyBox} testID={`campaigns-empty-${segment}`}>
195	            <Text style={[textStyles.body, { color: colors.ink70, textAlign: 'center' }]}>
196	              {emptyMessageFor(segment)}
197	            </Text>
198	          </View>
199	        ) : (
200	          <View style={styles.list}>
201	            {visible.map((row) => (
202	              <CampaignCard
203	                key={row.id}
204	                title={row.title}
205	                listerHandle={handle}
206	                priceCents={row.price_cents}
207	                currency={row.currency as CampaignCardCurrency}
208	                status={STATUS_PILL[row.status].pill}
209	                statusLabel={STATUS_PILL[row.status].label}
210	                meta={[
211	                  { label: 'applications', value: row.applications_count },
212	                  { label: 'submissions', value: row.submissions_count },
213	                ]}
214	                testID={`campaign-${row.id}`}
215	              />
216	            ))}
217	          </View>
218	        )}
219	      </ScrollView>
220	      <Fab onPress={onCreate} accessibilityLabel="Create campaign" testID="lister-fab-create" />
221	    </SafeAreaView>
222	  );
223	}
