63	// Feed cell per docs/design.md §5.1 — hard-shadow card, 2px ink border. Press
64	// behavior per §1.4 line 103: shadow collapses (3,3) → (0,0) while the card
65	// translates (3,3) to mimic a physical press. Same animated-shadowOpacity + fixed
66	// shadowOffset pattern as Button/Chip since iOS shadowOffset is not animatable
67	// through Reanimated.
68	export function CampaignCard({
69	  title,
70	  listerHandle,
71	  priceCents,
72	  currency = 'USD',
73	  preConditionSummary,
74	  status,
75	  statusLabel,
76	  meta,
77	  onPress,
78	  style,
79	  testID,
80	}: CampaignCardProps) {
81	  const reduced = useReducedMotion();
82	  const pressed = useSharedValue(0);
83	  const interactive = !!onPress;
84	
85	  const animatedStyle = useAnimatedStyle(() => {
86	    const v = pressed.value;
87	    return {
88	      transform: [{ translateX: v * 3 }, { translateY: v * 3 }],
89	      shadowOpacity: 1 - v,
90	    };
91	  });
92	
93	  const handlePressIn = useCallback(() => {
94	    if (!interactive) return;
95	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
96	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
97	  }, [interactive, pressed, reduced]);
98	
99	  const handlePressOut = useCallback(() => {
100	    if (!interactive) return;
101	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
102	  }, [interactive, pressed, reduced]);
103	
104	  return (
105	    <Pressable
106	      onPress={interactive ? onPress : undefined}
107	      onPressIn={handlePressIn}
108	      onPressOut={handlePressOut}
109	      disabled={!interactive}
110	      accessible={interactive}
111	      accessibilityRole={interactive ? 'button' : undefined}
112	      accessibilityLabel={interactive ? `${title} by ${listerHandle}` : undefined}
113	      testID={testID}
114	    >
115	      <Animated.View style={[styles.card, shadows.hard, animatedStyle, style]}>
116	        <Text style={[textStyles.h2, styles.title]} numberOfLines={2}>
117	          {title}
118	        </Text>
119	        <Text style={[textStyles.mono, styles.handle]} numberOfLines={1}>
120	          {listerHandle}
121	        </Text>
122	        {preConditionSummary ? (
123	          <Text style={[textStyles.caption, styles.preCondition]} numberOfLines={2}>
124	            {preConditionSummary}
125	          </Text>
126	        ) : null}
127	        <View style={styles.footerRow}>
128	          <Text style={[textStyles.h2, styles.price]}>{formatPrice(priceCents, currency)}</Text>
129	          {status ? <StatusPill status={status} label={statusLabel} /> : null}
130	        </View>
131	        {meta && meta.length > 0 ? (
132	          <Text
133	            style={[textStyles.caption, styles.meta]}
134	            numberOfLines={1}
135	            maxFontSizeMultiplier={1.3}
136	          >
137	            {meta.map((m) => `${m.value} ${m.label}`).join(' · ')}
138	          </Text>
139	        ) : null}
140	      </Animated.View>
141	    </Pressable>
142	  );
143	}
